+/// Principal - an identity making requests.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Principal {
+    /// Type of principal (e.g., "user", "agent", "service", "webhook")
+    pub kind: String,
+
+    /// Unique identifier for this principal
